import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.BeVX27ge.js";const m=JSON.parse('{"title":"Practice Simulation","description":"","frontmatter":{},"headers":[],"relativePath":"en/practice.md","filePath":"en/practice.md"}'),n={name:"en/practice.md"};function r(s,e,l,u,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="practice-simulation" tabindex="-1">Practice Simulation <a class="header-anchor" href="#practice-simulation" aria-label="Permalink to &quot;Practice Simulation&quot;">​</a></h1><blockquote><p>Hone your communication skills through simulated sales conversations with AI customers.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Practice Simulation is the core feature of AI Coach. You interact with an AI-driven virtual customer who responds realistically based on their configured attributes (age, occupation, income, personality traits), creating a safe environment to practice various sales scenarios.</p><h2 id="starting-a-session" tabindex="-1">Starting a Session <a class="header-anchor" href="#starting-a-session" aria-label="Permalink to &quot;Starting a Session&quot;">​</a></h2><ul><li><strong>&quot;Start Conversation&quot;</strong> button on the Dashboard.</li><li><strong>&quot;Retry&quot;</strong> or <strong>&quot;Continue&quot;</strong> buttons in History.</li></ul><hr><h2 id="scenario-selection" tabindex="-1">Scenario Selection <a class="header-anchor" href="#scenario-selection" aria-label="Permalink to &quot;Scenario Selection&quot;">​</a></h2><h3 id="random-persona" tabindex="-1">Random Persona <a class="header-anchor" href="#random-persona" aria-label="Permalink to &quot;Random Persona&quot;">​</a></h3><ul><li>The system automatically generates a randomized customer.</li><li>Ideal for quick practice sessions or when no specific target is needed.</li></ul><h3 id="custom-persona" tabindex="-1">Custom Persona <a class="header-anchor" href="#custom-persona" aria-label="Permalink to &quot;Custom Persona&quot;">​</a></h3><ul><li>Define customer attributes manually (e.g., high-income, married).</li><li>Opens the Customer Persona Setup panel.</li></ul><h3 id="retry-from-history" tabindex="-1">Retry (From History) <a class="header-anchor" href="#retry-from-history" aria-label="Permalink to &quot;Retry (From History)&quot;">​</a></h3><ul><li>Encounter the exact same customer from a previous session.</li><li>Useful for testing alternative strategies.</li></ul><h3 id="continue-from-history" tabindex="-1">Continue (From History) <a class="header-anchor" href="#continue-from-history" aria-label="Permalink to &quot;Continue (From History)&quot;">​</a></h3><ul><li>Resume an unfinished conversation.</li><li>The customer will faintly remember your previous conversation.</li></ul><hr><h2 id="customer-persona-setup" tabindex="-1">Customer Persona Setup <a class="header-anchor" href="#customer-persona-setup" aria-label="Permalink to &quot;Customer Persona Setup&quot;">​</a></h2><p>When creating a Custom Persona, any blank fields will be automatically filled by the AI.</p><ul><li><strong>Demographics</strong>: Age, Gender, Education, Income, Occupation.</li><li><strong>Personality (MBTI)</strong>: Extremely influential on communication and decision-making styles.</li><li><strong>Family</strong>: Marital Status, Children Count, Children&#39;s details.</li><li><strong>Relationship</strong>: Stranger vs. Family-Friends. If Family-Friends, a &quot;Relationship Description&quot; is required.</li></ul><hr><h2 id="chat-interface" tabindex="-1">Chat Interface <a class="header-anchor" href="#chat-interface" aria-label="Permalink to &quot;Chat Interface&quot;">​</a></h2><ul><li><strong>Left</strong>: Detailed customer profile sidebar.</li><li><strong>Center</strong>: Main conversation window.</li><li><strong>Top</strong>: Scenario orientation message and Session timer.</li><li><strong>Top Right</strong>: &quot;End Conversation&quot; button.</li></ul><h3 id="safety-rules" tabindex="-1">Safety Rules <a class="header-anchor" href="#safety-rules" aria-label="Permalink to &quot;Safety Rules&quot;">​</a></h3><p>The AI platform employs a content moderation engine.</p><ul><li>Do not send real PII (IDs, phone numbers).</li><li>Do not attempt jailbreaks or send inappropriate content. Violations will result in the message being blocked.</li></ul><hr><h2 id="sales-stages" tabindex="-1">Sales Stages <a class="header-anchor" href="#sales-stages" aria-label="Permalink to &quot;Sales Stages&quot;">​</a></h2><p>Based on the administrator&#39;s configuration (e.g., Ice-breaking, Needs Discovery, Proposing Options, Handling Objections, Closing).</p><ul><li>Stage assessment is conducted <strong>AFTER</strong> the conversation ends, not in real-time. Just focus on a natural flow!</li></ul><hr><h2 id="ending-the-conversation" tabindex="-1">Ending the Conversation <a class="header-anchor" href="#ending-the-conversation" aria-label="Permalink to &quot;Ending the Conversation&quot;">​</a></h2><ul><li><strong>Manual End</strong>: Click &quot;End Conversation&quot; &gt; Confirm.</li><li><strong>Customer-Initiated End</strong>: When the AI customer attempts to hang up, you&#39;ll be prompted to either &quot;Try to Continue&quot; or &quot;Accept End&quot;.</li></ul><p>Once concluded, the system automatically redirects you to the Evaluation Report.</p>',34)])])}const p=t(n,[["render",r]]);export{m as __pageData,p as default};
